INSERT INTO public.products (id, name, slug, description, price, compare_price, stock, sku, category_id, images, tags, rating, review_count, is_featured) VALUES
  ('20000000-0000-0000-0000-000000000001', 'Wireless Bluetooth Headphones', 'wireless-bluetooth-headphones', 'Premium wireless headphones with active noise cancellation, 30-hour battery life, and crystal-clear audio.', 149.99, 199.99, 50, 'ELEC-001', '10000000-0000-0000-0000-000000000001', '["https://images.unsplash.com/photo-1505740420928-5e560c06d30e?w=600","https://images.unsplash.com/photo-1484704849700-f032a568e944?w=600"]', '["wireless","headphones","bluetooth","audio"]', 4.5, 120, true),
  ('20000000-0000-0000-0000-000000000002', 'Smart Watch Pro', 'smart-watch-pro', 'Advanced smartwatch with health monitoring, GPS, and 7-day battery life. Water resistant to 50m.', 299.99, 349.99, 30, 'ELEC-002', '10000000-0000-0000-0000-000000000001', '["https://images.unsplash.com/photo-1523275335684-37898b6baf30?w=600","https://images.unsplash.com/photo-1579586337278-3befd40fd17a?w=600"]', '["smartwatch","fitness","health","wearable"]', 4.7, 85, true),
  ('20000000-0000-0000-0000-000000000003', '4K Action Camera', '4k-action-camera', 'Ultra HD action camera with 60fps recording, waterproof case included. Perfect for adventures.', 249.99, 299.99, 40, 'ELEC-003', '10000000-0000-0000-0000-000000000001', '["https://images.unsplash.com/photo-1526170375885-4d8ecf77b99f?w=600","https://images.unsplash.com/photo-1502920917128-1aa500764cbd?w=600"]', '["camera","4k","action","waterproof"]', 4.3, 67, false),
  ('20000000-0000-0000-0000-000000000004', 'Wireless Earbuds Pro', 'wireless-earbuds-pro', 'True wireless earbuds with ANC, transparency mode, and premium sound quality. 24h total battery.', 179.99, 229.99, 100, 'ELEC-004', '10000000-0000-0000-0000-000000000001', '["https://images.unsplash.com/photo-1590658268037-6bf12165a8df?w=600","https://images.unsplash.com/photo-1606220588913-b3aacb4d2f46?w=600"]', '["earbuds","wireless","anc","audio"]', 4.6, 203, true),
  ('20000000-0000-0000-0000-000000000005', 'Portable Power Bank 20000mAh', 'portable-power-bank-20000mah', 'High capacity power bank with fast charging. Charge 3 devices simultaneously.', 49.99, 69.99, 200, 'ELEC-005', '10000000-0000-0000-0000-000000000001', '["https://images.unsplash.com/photo-1609091839311-d5365f9ff1c5?w=600"]', '["power-bank","portable","fast-charge","accessory"]', 4.4, 156, false);
